    [ValueTracking] Update `Ordered` when both operands are non-NaN. (#143349)

    When the original predicate is ordered and both operands are non-NaN,
    `Ordered` should be set to true. This variable still matters even if
    both operands are non-NaN because FMF only applies to select, not fcmp.

    Closes https://github.com/llvm/llvm-project/issues/143123.

diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index d6bb852e208f..d8c1096049dc 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8660,6 +8660,7 @@ static SelectPatternResult matchSelectPattern(CmpInst::Predicate Pred,
     if (LHSSafe && RHSSafe) {
       // Both operands are known non-NaN.
       NaNBehavior = SPNB_RETURNS_ANY;
+      Ordered = CmpInst::isOrdered(Pred);
     } else if (CmpInst::isOrdered(Pred)) {
       // An ordered comparison will return false when given a NaN, so it
       // returns the RHS.

tests.test_body:
define i1 @test_fcmp_ord_select_fcmp_oeq_var_const(double %x) {
  %cmp1 = fcmp ord double %x, 0.000000e+00
  %sel = select i1 %cmp1, double %x, double 0.000000e+00
  %cmp2 = fcmp oeq double %sel, 1.000000e+00
  ret i1 %cmp2
}

define float @test_select_nnan_nsz_fcmp_olt(float %x) {
  %cmp = fcmp olt float %x, 0.000000e+00
  %sel = select nnan nsz i1 %cmp, float %x, float -0.000000e+00
  ret float %sel
}

define float @test_select_nnan_nsz_fcmp_ult(float %x) {
  %cmp = fcmp ult float %x, 0.000000e+00
  %sel = select nnan nsz i1 %cmp, float %x, float -0.000000e+00
  ret float %sel
}

define i1 @test_fcmp_select_var_const_unordered(double %x, double %y) {
  %cmp1 = fcmp ult double %x, 0x3E80000000000000
  %sel = select i1 %cmp1, double %y, double 0.000000e+00
  %cmp2 = fcmp ugt double %sel, 0x3E80000000000000
  ret i1 %cmp2
}
